// === Convenience: compute CID + store via IPFS HTTP API ===

const IPFS_API: &str = "http://127.0.0.1:5001";

pub fn ipfs_add(content: &str) -> Option<String> {
    ipfs_add_bytes(content.as_bytes())
}

pub fn ipfs_add_bytes(data: &[u8]) -> Option<String> {
    // Try to actually store via IPFS daemon HTTP API
    if let Some(cid) = ipfs_http_add(data) {
        return Some(cid);
    }
    // Fallback: compute CID locally (content not retrievable via ipfs cat)
    Some(ipfs_cid_bytes(data))
}

/// Add content to IPFS via HTTP API, returns real CID
fn ipfs_http_add(data: &[u8]) -> Option<String> {
    let client = reqwest::blocking::Client::builder()
        .timeout(std::time::Duration::from_secs(5)).build().ok()?;
    let form = reqwest::blocking::multipart::Form::new()
        .part("file", reqwest::blocking::multipart::Part::bytes(data.to_vec()).file_name("data"));
    let resp = client.post(format!("{}/api/v0/add?cid-version=1", IPFS_API))
        .multipart(form).send().ok()?;
    let json: serde_json::Value = resp.json().ok()?;
    json["Hash"].as_str().map(|s| s.to_string())
}

/// Retrieve content from IPFS via HTTP API
pub fn ipfs_cat(cid: &str) -> Option<Vec<u8>> {
    let client = reqwest::blocking::Client::builder()
        .timeout(std::time::Duration::from_secs(10)).build().ok()?;
    let resp = client.post(format!("{}/api/v0/cat?arg={}", IPFS_API, cid))
        .send().ok()?;
    if !resp.status().is_success() { return None; }
    resp.bytes().ok().map(|b| b.to_vec())
}

pub fn local_cid(data: &[u8]) -> String {
    let hash = Sha256::digest(data);
    format!("bafk{}", hex::encode(&hash[..16]))
}

