use std::io::Cursor;

pub struct IpfsStore {
    client: IpfsClient,
}

impl IpfsStore {
    pub fn new() -> Result<Self, Box<dyn std::error::Error>> {
        let client = IpfsClient::from_str("http://127.0.0.1:5001")?;
        Ok(Self { client })
    }

