// IPFS - Pure Rust content addressing with DASL/CBOR wrapping
// No external calls. Computes real IPFS-compatible CIDs via UnixFS encoding.
use sha2::{Sha256, Digest};
use serde::{Serialize, Deserialize};

/// Content addressing backend trait
pub trait ContentStore: Send + Sync {
    fn name(&self) -> &str;
    fn add(&self, data: &[u8]) -> Option<String>;
}

// === Pure Rust IPFS CID (UnixFS compatible) ===

/// Compute CID matching `ipfs add` output for small files (<256KB).
/// Encodes as UnixFS protobuf → dag-pb → sha256 → CIDv1 base32.
pub fn ipfs_cid_bytes(data: &[u8]) -> String {
    // 1. UnixFS protobuf: Type=File(2), Data=content, filesize=len
    let unixfs = encode_unixfs(data);
    // 2. dag-pb Node: Data field (field 1 in dag-pb is Links, field 2 is Data)
    let dagpb = encode_dagpb(&unixfs);
    // 3. SHA256 multihash
    let hash = Sha256::digest(&dagpb);
    // 4. CIDv1: version(1) + dag-pb codec(0x70) + sha256 multihash
    let mut cid = vec![0x01, 0x70, 0x12, 0x20];
    cid.extend_from_slice(&hash);
    format!("b{}", data_encoding::BASE32_NOPAD.encode(&cid).to_lowercase())
}

/// Encode UnixFS protobuf (Type=File, Data, filesize)
fn encode_unixfs(data: &[u8]) -> Vec<u8> {
    let mut buf = Vec::new();
    // field 1 (Type): varint, wire type 0, value 2 (File)
    buf.push(0x08); // field 1, wire type 0
    buf.push(0x02); // Type::File = 2
    // field 2 (Data): bytes
    buf.push(0x12); // field 2, wire type 2
    encode_varint(&mut buf, data.len() as u64);
    buf.extend_from_slice(data);
    // field 3 (filesize): varint
    buf.push(0x18); // field 3, wire type 0
    encode_varint(&mut buf, data.len() as u64);
    buf
}

/// Encode dag-pb Node (just Data field, no Links for leaf nodes)
fn encode_dagpb(data: &[u8]) -> Vec<u8> {
    let mut buf = Vec::new();
    // field 1 = Links (repeated, empty for leaf)
    // field 2 = Data: bytes
    buf.push(0x0a); // field 1, wire type 2... wait, dag-pb field numbering:
    // Actually in dag-pb: field 2 = Data, field 1 = Links (but we skip links)
    buf.clear();
    buf.push(0x12); // field 2, wire type 2
    encode_varint(&mut buf, data.len() as u64);
    buf.extend_from_slice(data);
    buf
}

fn encode_varint(buf: &mut Vec<u8>, mut val: u64) {
    loop {
        let byte = (val & 0x7F) as u8;
        val >>= 7;
        if val == 0 { buf.push(byte); break; }
        buf.push(byte | 0x80);
    }
}

// === DASL/CBOR envelope ===

/// DASL/CBOR wrapped paste object
#[derive(Serialize, Deserialize)]
pub struct DaslObject {
    /// 0xDA51 prefix marker
    pub prefix: u64,
    /// DASL type (3 = nested CID)
    pub dasl_type: u8,
    /// Orbifold coordinates (l mod 71, m mod 59, n mod 47)
    pub orbifold: (u64, u64, u64),
    /// Bott periodicity index (0-7)
    pub bott: u8,
    /// Content bytes
    #[serde(with = "serde_bytes")]
    pub data: Vec<u8>,
    /// Content IPFS CID
    pub cid: String,
    /// DASL address (64-bit)
    pub dasl: String,
}

/// Wrap content in DASL/CBOR envelope, return (cbor_bytes, ipfs_cid)
pub fn wrap_dasl_cbor(data: &[u8]) -> (Vec<u8>, String) {
    let cid = ipfs_cid_bytes(data);
    let dasl_addr = crate::dasl::dasl_cid(data);
    let (l, m, n) = crate::dasl::orbifold_coords(data);
    let hash = Sha256::digest(data);
    let bott = hash[2] % 8;

    let obj = DaslObject {
        prefix: 0xDA51,
        dasl_type: 3,
        orbifold: (l, m, n),
        bott,
        data: data.to_vec(),
        cid: cid.clone(),
        dasl: dasl_addr,
    };

    let mut cbor = Vec::new();
    ciborium::into_writer(&obj, &mut cbor).unwrap_or_default();
    (cbor, cid)
}

