use wasm_bindgen::prelude::*;
use serde::{Deserialize, Serialize};
use sha2::{Sha256, Digest};
use base64::{Engine, engine::general_purpose::STANDARD as B64};

// === Tape / Kansas City Standard FSK ===
// 1200 Hz = 0, 2400 Hz = 1. 300 baud. 8N1 framing.

const SAMPLE_RATE: u32 = 44100;
const BAUD: u32 = 300;
const FREQ_ZERO: f32 = 1200.0;
const FREQ_ONE: f32 = 2400.0;
const SAMPLES_PER_BIT: u32 = SAMPLE_RATE / BAUD; // 147

fn fsk_encode_bit(bit: bool, samples: &mut Vec<i16>) {
    let freq = if bit { FREQ_ONE } else { FREQ_ZERO };
    let n = SAMPLES_PER_BIT;
    for i in 0..n {
        let t = i as f32 / SAMPLE_RATE as f32;
        let val = (2.0 * core::f32::consts::PI * freq * t).sin() * 24000.0;
        samples.push(val as i16);
    }
}

fn fsk_encode_byte(byte: u8, samples: &mut Vec<i16>) {
    fsk_encode_bit(false, samples); // start bit
    for i in 0..8 {
        fsk_encode_bit((byte >> i) & 1 == 1, samples);
    }
    fsk_encode_bit(true, samples); // stop bit
}

/// Encode data as KCS FSK audio samples (i16 PCM mono 44100Hz)
fn tape_encode(data: &[u8]) -> Vec<i16> {
    let mut samples = Vec::new();
    // Leader tone: 1 second of 2400Hz (mark)
    for _ in 0..(SAMPLE_RATE / SAMPLES_PER_BIT) {
        fsk_encode_bit(true, &mut samples);
    }
    // Length prefix (4 bytes big-endian)
    let len = data.len() as u32;
    for &b in &len.to_be_bytes() {
        fsk_encode_byte(b, &mut samples);
    }
    // Data
    for &b in data {
        fsk_encode_byte(b, &mut samples);
    }
    // Trailer: 0.5s mark
    for _ in 0..(SAMPLE_RATE / SAMPLES_PER_BIT / 2) {
        fsk_encode_bit(true, &mut samples);
    }
    samples
}

/// Decode KCS FSK audio samples back to data
fn tape_decode(samples: &[i16]) -> Option<Vec<u8>> {
    // Zero-crossing frequency detection per bit window
    let mut bits = Vec::new();
    let window = SAMPLES_PER_BIT as usize;
    let mut pos = 0;
    while pos + window <= samples.len() {
        let mut crossings = 0u32;
        for i in 1..window {
            if (samples[pos + i] >= 0) != (samples[pos + i - 1] >= 0) {
                crossings += 1;
            }
        }
        // 1200Hz in 147 samples ≈ 4 crossings, 2400Hz ≈ 8 crossings
        bits.push(crossings > 6);
        pos += window;
    }

    // Skip leader (consecutive 1s)
    let data_start = bits.iter().position(|&b| !b)?;

    // Decode 8N1 frames
    let mut bytes = Vec::new();
    let mut i = data_start;
    while i + 10 <= bits.len() {
        if bits[i] { i += 1; continue; } // scan for start bit (0)
        let mut byte = 0u8;
        for bit in 0..8 {
            if bits[i + 1 + bit] { byte |= 1 << bit; }
        }
        // bits[i+9] should be stop bit (1)
        bytes.push(byte);
        i += 10;
    }

    if bytes.len() < 4 { return None; }
    let len = u32::from_be_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]) as usize;
    if bytes.len() < 4 + len { return None; }
    Some(bytes[4..4 + len].to_vec())
}

/// Pack i16 PCM samples into a WAV file (mono, 16-bit, 44100Hz)
fn samples_to_wav(samples: &[i16]) -> Vec<u8> {
    let data_len = (samples.len() * 2) as u32;
    let file_len = 36 + data_len;
    let mut wav = Vec::with_capacity(file_len as usize + 8);
    wav.extend_from_slice(b"RIFF");
    wav.extend_from_slice(&file_len.to_le_bytes());
    wav.extend_from_slice(b"WAVE");
    wav.extend_from_slice(b"fmt ");
    wav.extend_from_slice(&16u32.to_le_bytes()); // chunk size
    wav.extend_from_slice(&1u16.to_le_bytes());  // PCM
