const BAUD: u32 = 300;
const FREQ_ZERO: f32 = 1200.0;
const FREQ_ONE: f32 = 2400.0;
const SAMPLES_PER_BIT: u32 = SAMPLE_RATE / BAUD; // 147

fn fsk_encode_bit(bit: bool, samples: &mut Vec<i16>) {
    let freq = if bit { FREQ_ONE } else { FREQ_ZERO };
    let n = SAMPLES_PER_BIT;
    for i in 0..n {
        let t = i as f32 / SAMPLE_RATE as f32;
        let val = (2.0 * core::f32::consts::PI * freq * t).sin() * 24000.0;
        samples.push(val as i16);
    }
}

fn fsk_encode_byte(byte: u8, samples: &mut Vec<i16>) {
    fsk_encode_bit(false, samples); // start bit
    for i in 0..8 {
        fsk_encode_bit((byte >> i) & 1 == 1, samples);
    }
    fsk_encode_bit(true, samples); // stop bit
}

/// Encode data as KCS FSK audio samples (i16 PCM mono 44100Hz)
fn tape_encode(data: &[u8]) -> Vec<i16> {
    let mut samples = Vec::new();
    // Leader tone: 1 second of 2400Hz (mark)
    for _ in 0..(SAMPLE_RATE / SAMPLES_PER_BIT) {
        fsk_encode_bit(true, &mut samples);
    }
    // Length prefix (4 bytes big-endian)
    let len = data.len() as u32;
    for &b in &len.to_be_bytes() {
        fsk_encode_byte(b, &mut samples);
    }
    // Data
    for &b in data {
        fsk_encode_byte(b, &mut samples);
    }
    // Trailer: 0.5s mark
    for _ in 0..(SAMPLE_RATE / SAMPLES_PER_BIT / 2) {
        fsk_encode_bit(true, &mut samples);
    }
    samples
}

