            ).count();
            let freq_est = crossings as f32 * SAMPLE_RATE as f32 / (2.0 * chunk as f32);
            // Find closest digit
            let digit = NUM_FREQS.iter().enumerate()
                .min_by_key(|(_, &f)| ((f - freq_est).abs() * 100.0) as u32)
                .map(|(i, _)| i as u8)
                .unwrap_or(0);
