// -- Tape --
let lastTapeWav = null;
let lastNumWav = null;

function downloadWav(bytes, name) {
  const blob = new Blob([bytes], {type: 'audio/wav'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = name;
  a.click();
  URL.revokeObjectURL(a.href);
}

async function shareToPastebin(wavBytes, title) {
  const b64 = btoa(String.fromCharCode(...wavBytes));
  const url = '/pastebin/upload';
  try {
    const form = new FormData();
    form.append('file', new Blob([wavBytes], {type:'audio/wav'}), title + '.wav');
    const resp = await fetch(url, {method:'POST', body: form});
    const json = await resp.json();
    set('tape-out', `Shared: ${json.url || json.id || 'ok'}`);
  } catch(e) {
    // Fallback: store locally
    const cid = pad.store_paste(b64);
    set('tape-out', `Stored locally: ${cid} (pastebin unreachable)`);
  }
}

