window.doNumSpeak = async () => {
  stopAll();
  const groups = pad.to_number_groups(val());
  set('num-groups', groups);

  let text = 'Attention. Attention. Message follows. ';
  for (const c of groups.split(' ')) {
    text += c.split('').join('. ') + '. . ';
  }
  text += 'End of message. End of message.';

  // Capture speech to WAV via MediaRecorder on audio destination
  const ctx = new AudioContext();
  const dest = ctx.createMediaStreamDestination();
  const recorder = new MediaRecorder(dest.stream, {mimeType: 'audio/webm'});
  const chunks = [];
  recorder.ondataavailable = e => { if (e.data.size) chunks.push(e.data); };
  recorder.onstop = async () => {
    const blob = new Blob(chunks, {type: 'audio/webm'});
    const buf = new Uint8Array(await blob.arrayBuffer());
    lastSpeechWav = buf;
    // Show download button
    const audio = $('num-audio');
    audio.src = URL.createObjectURL(blob);
    audio.style.display = 'block';
    set('num-groups', groups + ' → 🎙 Speech captured (' + buf.length + ' bytes)');
    const cid = pad.ipfs_put_typed(buf, 'audio/webm');
    set('num-groups', $('num-groups').textContent + ' → IPFS: ' + cid);
  };

  // Route speech through AudioContext so MediaRecorder captures it
  const source = ctx.createMediaStreamSource(dest.stream);
  recorder.start();

  const synth = window.speechSynthesis;
  const utt = new SpeechSynthesisUtterance(text);
  utt.rate = 0.7;
  utt.pitch = 0.8;
  utt.onend = () => { setTimeout(() => recorder.stop(), 200); };
  synth.speak(utt);
};
window.doSpeechDl = () => {
  if (lastSpeechWav) {
    const blob = new Blob([lastSpeechWav], {type: 'audio/webm'});
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'numbers-speech-' + Date.now() + '.webm';
    a.click();
  }
};

